request:
REM 切换到项目根目录
cd /d "${{variables.FULL_TMR_PTAH}}\${{variables.AssetToolPath}}"

REM 设置Python路径
set PYTHONPATH=%PYTHONPATH%;${{TMR_REPOSITORY_FOLDER}}\${{variables.AssetToolPath}}

REM 确保Intermediate目录存在
if not exist "Intermediate" mkdir "Intermediate"
if not exist "Intermediate\${{variables.Version}}" mkdir "Intermediate\${{variables.Version}}"

REM 显示当前路径和参数信息
echo 当前工作目录: %CD%
echo 版本号: ${{variables.Version}}
echo 输入目录: ${{TMR_REPOSITORY_FOLDER}}\${{variables.AssetToolPath}}\Intermediate\${{variables.Version}}
echo 输出目录: ${{TMR_REPOSITORY_FOLDER}}\${{variables.AssetToolPath}}\Intermediate\${{variables.Version}}

REM 执行Python脚本
python3 "Other/Pipe/Pipe_MergeAndStdAssetPak.py" --VERSION="${{variables.Version}}"

REM 检查执行结果 
if %ERRORLEVEL% neq 0 (  
    echo 错误: Python脚本执行失败，退出码: %ERRORLEVEL%
    exit /b %ERRORLEVEL%
) else (
    echo 成功: Python脚本执行完成
)
